/// Return a stable snapshot of all live processes known to the pid table.
pub fn all_processes() -> Vec<Arc<ProcessControlBlock>> {
    let map = PID2PCB.exclusive_access();
    map.values().cloned().collect()
}

/// Deliver expired process alarms scheduled by ITIMER_REAL.
pub fn check_process_alarms(now_us: usize) {
    let processes: Vec<_> = {
        let map = PID2PCB.exclusive_access();
        map.values().cloned().collect()
    };
    for process in processes {
        let mut inner = process.inner_exclusive_access();
        let Some(deadline) = inner.alarm_deadline_us else {
            continue;
        };
        if deadline > now_us {
            continue;
        }
        inner.alarm_deadline_us = None;
        if let Some(flag) = SignalFlags::from_signal(14) {
            inner.signals |= flag;
        }
        for task in inner.tasks.iter().flatten() {
            let mut task_inner = task.inner_exclusive_access();
            if task_inner.task_status == TaskStatus::Blocked {
                task_inner.task_status = TaskStatus::Ready;
                drop(task_inner);
                add_task(Arc::clone(task));
            }
        }
    }
}

fn wake_blocked_tasks(process: &Arc<ProcessControlBlock>) {
    let tasks: Vec<_> = process
        .inner_exclusive_access()
        .tasks
        .iter()
        .flatten()
        .cloned()
        .collect();
    for task in tasks {
        wakeup_task(task);
    }
}

/// Make current task suspended and switch to the next task
pub fn suspend_current_and_run_next() {
    // There must be an application running.
    let task = take_current_task().unwrap();

    // ---- access current TCB exclusively
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut TaskContext;
    // Change status to Ready
    task_inner.task_status = TaskStatus::Ready;
    drop(task_inner);
    // ---- release current TCB

    // push back to ready queue.
    add_task(task);
    // jump to scheduling cycle
    schedule(task_cx_ptr);
    exit_current_if_sigkill_pending();
}

/// Make current task blocked and switch to the next task.
pub fn block_current_and_run_next() {
    let task = take_current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    let task_cx_ptr = &mut task_inner.task_cx as *mut TaskContext;
    task_inner.task_status = TaskStatus::Blocked;
    drop(task_inner);
    schedule(task_cx_ptr);
    exit_current_if_sigkill_pending();
}

use crate::board::QEMUExit;

/// Exit the current 'Running' task and run the next task in task list.
pub fn exit_current_and_run_next(exit_code: i32) {
    trace!(
        "kernel: pid[{}] exit_current_and_run_next",
        current_task().unwrap().process.upgrade().unwrap().getpid()
    );
    // take from Processor
    let task = take_current_task().unwrap();
    let mut task_inner = task.inner_exclusive_access();
    let process = task.process.upgrade().unwrap();
    let tid = task_inner.res.as_ref().unwrap().tid;
    let clear_child_tid = task_inner.clear_child_tid;
    if clear_child_tid != 0 {
        let token = process.inner_exclusive_access().memory_set.token();
        if let Some(pa) = PageTable::from_token(token).translate_va(VirtAddr::from(clear_child_tid))
        {
            *pa.get_mut::<i32>() = 0;
            wake_futex_waiters(clear_child_tid, 1);
        }
    }
    // record exit code
    task_inner.exit_code = Some(exit_code);
    task_inner.res = None;
    // here we do not remove the thread since we are still using the kstack
    // it will be deallocated when sys_waittid is called
    drop(task_inner);

    // Move the task to stop-wait status, to avoid kernel stack from being freed
    if tid == 0 {
        add_stopping_task(task);
    } else {
        drop(task);
    }
    // however, if this is the main thread of current process
    // the process should terminate at once
    if tid == 0 {
        let pid = process.getpid();
        let is_judge_root = judge::is_judge_root(&process);
        {
            let mut process_inner = process.inner_exclusive_access();
            // Make the exit visible to the parent before any further teardown.
            process_inner.is_zombie = true;
            process_inner.exit_code = exit_code;
            if let Some(parent) = process_inner.parent.as_ref().and_then(|parent| parent.upgrade())
            {
                wake_blocked_tasks(&parent);
            }
        }
        if pid == IDLE_PID {
            println!(
                "[kernel] Idle process exit with exit_code {} ...",
                exit_code
            );
            if exit_code != 0 {
                //crate::sbi::shutdown(255); //255 == -1 for err hint
                crate::board::QEMU_EXIT_HANDLE.exit_failure();
            } else {
                //crate::sbi::shutdown(0); //0 for success hint
                crate::board::QEMU_EXIT_HANDLE.exit_success();
            }
        }
        if is_judge_root {
            judge::finish_judge_process(pid, exit_code);
        }
        remove_from_pid2process(pid);
        let process_inner = process.inner_exclusive_access();
        {
            // orphan child processes if their top-level test exits first
            for child in process_inner.children.iter() {
                child.inner_exclusive_access().parent = None;
            }
        }

        // deallocate user res (including tid/trap_cx/ustack) of all threads
        // it has to be done before we dealloc the whole memory_set
        // otherwise they will be deallocated twice
        let mut recycle_res = Vec::<TaskUserRes>::new();
        for task in process_inner.tasks.iter().filter(|t| t.is_some()) {
            let task = task.as_ref().unwrap();
            // if other tasks are Ready in TaskManager or waiting for a timer to be
            // expired, we should remove them.
            //
            // Mention that we do not need to consider Mutex/Semaphore since they
            // are limited in a single process. Therefore, the blocked tasks are
            // removed when the PCB is deallocated.
            trace!("kernel: exit_current_and_run_next .. remove_inactive_task");
            remove_inactive_task(Arc::clone(&task));
            let mut task_inner = task.inner_exclusive_access();
            if let Some(res) = task_inner.res.take() {
                recycle_res.push(res);
            }
        }
