/// Per-process file descriptor limit used for Linux EMFILE compatibility.
pub const MAX_FD: usize = 128;

/// Process Control Block
pub struct ProcessControlBlock {
    /// immutable
    pub pid: PidHandle,
    /// mutable
    inner: UPSafeCell<ProcessControlBlockInner>,
}

/// Minimal per-process time namespace offsets used by Linux time namespace tests.
#[derive(Clone, Copy, Default)]
pub struct TimeNamespace {
    /// Offset in seconds for CLOCK_MONOTONIC-derived clocks.
    pub monotonic_offset_sec: isize,
    /// Offset in seconds for CLOCK_BOOTTIME.
    pub boottime_offset_sec: isize,
}

/// Inner of Process Control Block
pub struct ProcessControlBlockInner {
    /// is zombie?
    pub is_zombie: bool,
    /// memory set(address space)
    pub memory_set: MemorySet,
    /// parent process
    pub parent: Option<Weak<ProcessControlBlock>>,
    /// children process
    pub children: Vec<Arc<ProcessControlBlock>>,
    /// exit code
    pub exit_code: i32,
    /// file descriptor table
    pub fd_table: Vec<Option<Arc<dyn File + Send + Sync>>>,
    /// Linux open status flags associated with each file descriptor.
    pub fd_flags: Vec<u32>,
    /// soft file descriptor limit for RLIMIT_NOFILE.
    pub fd_limit: usize,
    /// current working directory
    pub cwd: String,
    /// executable path used by readlinkat("/proc/self/exe")
    pub exe_path: String,
    /// Scheduling priority hint. Lower values mean higher priority.
    pub priority: isize,
    /// Process group id for POSIX process-group compatibility.
    pub pgid: usize,
    /// Real user id used by Linux credential syscalls.
    pub uid: u32,
    /// Effective user id used for permission checks and file ownership.
    pub euid: u32,
    /// Saved user id used by Linux credential syscalls.
    pub suid: u32,
    /// Real group id used by Linux credential syscalls.
    pub gid: u32,
    /// Effective group id used for permission checks and file ownership.
    pub egid: u32,
    /// Saved group id used by Linux credential syscalls.
    pub sgid: u32,
    /// Process file mode creation mask.
    pub umask: u32,
    /// signal flags
    pub signals: SignalFlags,
    /// Linux rt_sigaction compatibility storage.
    pub sigactions: [[usize; 4]; 65],
    /// Linux rt_sigprocmask compatibility storage.
    pub sigmask: usize,
    /// Linux robust futex list head, stored for ABI compatibility.
    pub robust_list: usize,
    /// Absolute microsecond deadline for ITIMER_REAL/SIGALRM.
    pub alarm_deadline_us: Option<usize>,
    /// Active time namespace offsets applied to this process.
    pub time_namespace: TimeNamespace,
    /// Time namespace offsets that children enter after CLONE_NEWTIME.
    pub time_namespace_for_children: TimeNamespace,
    /// initial program break
    pub heap_bottom: usize,
    /// current program break
    pub program_brk: usize,
    /// next base address for anonymous/file-backed mmap allocations
    pub next_mmap: usize,
    /// Next Linux-visible thread id for CLONE_THREAD tasks.
    pub next_linux_tid: usize,
    /// File-backed shared mmap regions that need writeback on munmap.
    pub mmap_files: Vec<MmapFileRegion>,
    /// tasks(also known as threads)
    pub tasks: Vec<Option<Arc<TaskControlBlock>>>,
    /// task resource allocator
    pub task_res_allocator: RecycleAllocator,
    /// mutex list
    pub mutex_list: Vec<Option<Arc<dyn Mutex>>>,
    /// semaphore list
    pub semaphore_list: Vec<Option<Arc<Semaphore>>>,
    /// condvar list
    pub condvar_list: Vec<Option<Arc<Condvar>>>,
    /// top-level judge task spawned by the kernel
    pub judge_root: bool,
}

/// Metadata for a file-backed shared mmap region.
#[derive(Clone)]
pub struct MmapFileRegion {
    /// Start virtual address of the mapping.
    pub start: usize,
    /// Requested mapping length.
    pub len: usize,
    /// File offset used for the mapping.
    pub offset: usize,
    /// File object backing this mapping.
    pub file: Arc<dyn File + Send + Sync>,
}

impl ProcessControlBlockInner {
    #[allow(unused)]
    /// get the address of app's page table
    pub fn get_user_token(&self) -> usize {
        self.memory_set.token()
    }
    /// allocate a new file descriptor
    pub fn alloc_fd(&mut self) -> Option<usize> {
        if let Some(fd) = (0..self.fd_table.len()).find(|fd| self.fd_table[*fd].is_none()) {
            Some(fd)
        } else {
            if self.fd_table.len() >= self.fd_limit.min(MAX_FD) {
                return None;
            }
            self.fd_table.push(None);
            Some(self.fd_table.len() - 1)
        }
    }
    /// allocate a new task id
    pub fn alloc_tid(&mut self) -> usize {
        self.task_res_allocator.alloc()
    }
    /// deallocate a task id
    pub fn dealloc_tid(&mut self, tid: usize) {
        self.task_res_allocator.dealloc(tid)
    }
    /// Allocate a Linux-visible thread id that is not tied to recycled slots.
    pub fn alloc_linux_tid(&mut self) -> usize {
        let tid = self.next_linux_tid;
        self.next_linux_tid = self.next_linux_tid.saturating_add(1);
        tid
    }
    /// the count of tasks(threads) in this process
    pub fn thread_count(&self) -> usize {
        self.tasks.len()
    }
    /// get a task with tid in this process
    pub fn get_task(&self, tid: usize) -> Arc<TaskControlBlock> {
        self.tasks[tid].as_ref().unwrap().clone()
    }
}

