lazy_static! {
    /// The kernel's initial memory mapping(kernel address space)
    pub static ref KERNEL_SPACE: Arc<UPSafeCell<MemorySet>> =
        Arc::new(unsafe { UPSafeCell::new(MemorySet::new_kernel()) });
}

/// the kernel token
pub fn kernel_token() -> usize {
    KERNEL_SPACE.exclusive_access().token()
}

/// address space
pub struct MemorySet {
    /// page table
    pub page_table: PageTable,
    /// areas
    pub areas: Vec<MapArea>,
}

/// Metadata needed to build a Linux-compatible initial user stack.
#[derive(Clone, Copy)]
pub struct ElfInfo {
    /// Entry address where the kernel transfers control.
    pub entry: usize,
    /// Original application entry address reported through auxv `AT_ENTRY`.
    pub at_entry: usize,
    /// Virtual address of the ELF program header table.
    pub phdr: usize,
    /// Size of each program header entry.
    pub phent: usize,
    /// Number of program header entries.
    pub phnum: usize,
    /// Base address where the ELF interpreter is loaded, or 0 for static ELF.
    pub at_base: usize,
    /// Virtual address of PT_TLS initialization image.
    pub tls_vaddr: usize,
    /// File-backed bytes in PT_TLS.
    pub tls_filesz: usize,
    /// Total PT_TLS memory size, including zeroed tbss.
    pub tls_memsz: usize,
    /// PT_TLS alignment.
    pub tls_align: usize,
    /// Base of the kernel-created static TLS area.
    pub tls_base: usize,
    /// Initial program break, placed after the loaded ELF image.
    pub heap_bottom: usize,
}

