fn default_file_metadata(mode: u32) -> FileMetadata {
    FileMetadata {
        mode: mode & 0o177777,
        uid: 0,
        gid: 0,
        nlink: 1,
    }
}

fn link_group_for(path: &str) -> String {
    LINK_GROUPS
        .exclusive_access()
        .get(path)
        .cloned()
        .unwrap_or_else(|| path.to_string())
}

fn refresh_link_counts(group: &str) {
    let count = LINK_GROUPS
        .exclusive_access()
        .values()
        .filter(|entry_group| entry_group.as_str() == group)
        .count()
        .max(1) as u32;
    let paths: Vec<String> = LINK_GROUPS
        .exclusive_access()
        .iter()
        .filter_map(|(path, entry_group)| {
            if entry_group.as_str() == group {
                Some(path.clone())
            } else {
                None
            }
        })
        .collect();
    let mut meta = FILE_META.exclusive_access();
    for path in paths {
        meta.entry(path)
            .or_insert_with(|| default_file_metadata(0o644))
            .nlink = count;
    }
}

fn ensure_file_metadata(path: &str, mode: u32) {
    let path = canonicalize_path(path);
    LINK_GROUPS
        .exclusive_access()
        .entry(path.clone())
        .or_insert_with(|| path.clone());
    FILE_META
        .exclusive_access()
        .entry(path.clone())
        .or_insert_with(|| default_file_metadata(mode));
    let group = link_group_for(path.as_str());
    refresh_link_counts(group.as_str());
}

/// Return tracked metadata for a path if the overlay knows about it.
pub fn file_metadata(path: &str) -> Option<FileMetadata> {
    let path = canonicalize_path(path);
    FILE_META.exclusive_access().get(path.as_str()).copied()
}

/// Ensure metadata exists for a path created through `openat`.
pub fn create_metadata(path: &str, mode: u32) {
    ensure_file_metadata(path, mode);
}

/// Change file mode bits for a tracked overlay path.
pub fn chmod_path(path: &str, mode: u32) -> bool {
    let path = canonicalize_path(path);
    if !mem_file_exists(path.as_str()) && !dir_exists(path.as_str()) {
        return false;
    }
    let group = link_group_for(path.as_str());
    let paths: Vec<String> = LINK_GROUPS
        .exclusive_access()
        .iter()
        .filter_map(|(entry_path, entry_group)| {
            if entry_group.as_str() == group.as_str() {
                Some(entry_path.clone())
            } else {
                None
            }
        })
        .collect();
    let mut meta = FILE_META.exclusive_access();
    if paths.is_empty() {
        let entry = meta
            .entry(path)
            .or_insert_with(|| default_file_metadata(mode));
        entry.mode = (entry.mode & 0o170000) | (mode & 0o7777);
    } else {
        for entry_path in paths {
            let entry = meta
                .entry(entry_path)
                .or_insert_with(|| default_file_metadata(mode));
            entry.mode = (entry.mode & 0o170000) | (mode & 0o7777);
        }
    }
    true
}

/// Change ownership metadata for a tracked overlay path.
pub fn chown_path(path: &str, uid: u32, gid: u32) -> bool {
    let path = canonicalize_path(path);
    if !mem_file_exists(path.as_str()) && !dir_exists(path.as_str()) {
        return false;
    }
    let group = link_group_for(path.as_str());
    let paths: Vec<String> = LINK_GROUPS
        .exclusive_access()
        .iter()
        .filter_map(|(entry_path, entry_group)| {
            if entry_group.as_str() == group.as_str() {
                Some(entry_path.clone())
            } else {
                None
