fn elf_interp_path(elf_data: &[u8]) -> Option<String> {
    let elf = xmas_elf::ElfFile::new(elf_data).ok()?;
    for i in 0..elf.header.pt2.ph_count() {
        let ph = elf.program_header(i).ok()?;
        if ph.get_type().ok()? != xmas_elf::program::Type::Interp {
            continue;
        }
        let start = ph.offset() as usize;
        let end = start.checked_add(ph.file_size() as usize)?;
        let bytes = elf_data.get(start..end)?;
        let nul = bytes
            .iter()
            .position(|byte| *byte == 0)
            .unwrap_or(bytes.len());
        return core::str::from_utf8(&bytes[..nul])
            .ok()
            .map(ToString::to_string);
    }
    None
}

fn resolve_elf_interp(exec_path: &str, interp_path: &str) -> String {
    if let Some(name) = interp_path.strip_prefix("/lib/") {
        if exec_path.starts_with("/glibc/") {
            return format!("/glibc/lib/{}", name);
        }
        if exec_path.starts_with("/musl/") {
            let mapped = format!("/musl/lib/{}", name);
            if open_file(mapped.as_str(), OpenFlags::RDONLY).is_some() {
                return mapped;
            }
            if name == "ld-musl-riscv64.so.1" {
                return String::from("/musl/lib/libc.so");
            }
        }
    }
    normalize_path(interp_path)
}

fn read_elf_interp(exec_path: &str, elf_data: &[u8]) -> Option<Vec<u8>> {
    let interp_path = elf_interp_path(elf_data)?;
    let mapped = resolve_elf_interp(exec_path, interp_path.as_str());
    open_file(mapped.as_str(), OpenFlags::RDONLY).map(|inode| inode.read_all())
}

