/// Wake up to `limit` tasks sleeping on a futex word.
pub fn wake_futex_waiters(uaddr: usize, limit: usize) -> usize {
    let mut woke = 0usize;
    let mut waiters = FUTEX_WAITERS.exclusive_access();
    if let Some(queue) = waiters.get_mut(&uaddr) {
        while woke < limit {
            let Some(task) = queue.pop_front() else {
                break;
            };
            wakeup_task(task);
            woke += 1;
        }
        if queue.is_empty() {
            waiters.remove(&uaddr);
        }
    }
    woke
}

fn remove_futex_waiter(uaddr: usize, task: &Arc<TaskControlBlock>) -> bool {
    let mut waiters = FUTEX_WAITERS.exclusive_access();
    let Some(queue) = waiters.get_mut(&uaddr) else {
        return false;
    };
    let removed = if let Some(pos) = queue
        .iter()
        .position(|waiter| Arc::as_ptr(waiter) == Arc::as_ptr(task))
    {
        queue.remove(pos);
        true
    } else {
        false
    };
    if queue.is_empty() {
        waiters.remove(&uaddr);
    }
    removed
}

fn read_futex_word(token: usize, uaddr: usize) -> Option<i32> {
    if uaddr == 0 || uaddr % core::mem::size_of::<i32>() != 0 {
        return None;
    }
    Some(*translated_ref(token, uaddr as *const i32))
}

fn futex_timespec_us(ts: &FutexTimeSpec, round_up: bool) -> Option<usize> {
    if ts.nsec >= 1_000_000_000 {
        return None;
    }
    let usec = if round_up {
        (ts.nsec.saturating_add(999)) / 1000
    } else {
        ts.nsec / 1000
    };
    Some(ts.sec.saturating_mul(1_000_000).saturating_add(usec))
}

fn monotonic_offset_us() -> isize {
    current_process()
        .inner_exclusive_access()
        .time_namespace
        .monotonic_offset_sec
        .saturating_mul(1_000_000)
}

fn raw_deadline_from_monotonic(deadline_us: usize) -> usize {
    (deadline_us as isize)
        .saturating_sub(monotonic_offset_us())
        .max(0) as usize
}

fn us_to_timer_ms(deadline_us: usize) -> usize {
    deadline_us.saturating_add(999) / 1000
}

