/// VirtIOBlock device driver strcuture for virtio_blk device
pub struct VirtIOBlock(UPSafeCell<VirtIOBlk<'static, VirtioHal>>);

lazy_static! {
    /// The global io data queue for virtio_blk device
    static ref QUEUE_FRAMES: UPSafeCell<Vec<FrameTracker>> = unsafe { UPSafeCell::new(Vec::new()) };
    static ref READ_BOUNCE_BUFFER: UPSafeCell<AlignedBlock> =
        unsafe { UPSafeCell::new(AlignedBlock([0; BLOCK_SIZE])) };
    static ref WRITE_BOUNCE_BUFFER: UPSafeCell<AlignedBlock> =
        unsafe { UPSafeCell::new(AlignedBlock([0; BLOCK_SIZE])) };
}

const BLOCK_SIZE: usize = 512;

#[repr(align(4096))]
struct AlignedBlock([u8; BLOCK_SIZE]);

impl BlockDevice for VirtIOBlock {
    /// Read a block from the virtio_blk device
    fn read_block(&self, block_id: usize, buf: &mut [u8]) {
        let mut bounce = READ_BOUNCE_BUFFER.exclusive_access();
        bounce.0.fill(0);
        let mut ok = false;
        for _ in 0..3 {
            if self
                .0
                .exclusive_access()
                .read_block(block_id, &mut bounce.0)
                .is_ok()
            {
                ok = true;
                break;
            }
        }
        let n = buf.len().min(BLOCK_SIZE);
        if ok {
            buf[..n].copy_from_slice(&bounce.0[..n]);
        } else {
            buf[..n].fill(0);
        }
    }
    ///
    fn write_block(&self, block_id: usize, buf: &[u8]) {
        let mut bounce = WRITE_BOUNCE_BUFFER.exclusive_access();
        bounce.0.fill(0);
        let n = buf.len().min(BLOCK_SIZE);
        bounce.0[..n].copy_from_slice(&buf[..n]);
        for _ in 0..3 {
            if self
                .0
                .exclusive_access()
                .write_block(block_id, &bounce.0)
                .is_ok()
            {
                break;
            }
        }
    }
}

impl VirtIOBlock {
    /// Create a new VirtIOBlock driver with base address for virtio_blk device
    pub fn new(base_addr: usize) -> Self {
        Self::try_new(base_addr).unwrap()
    }

    /// Try to create a new VirtIOBlock driver.
    pub fn try_new(base_addr: usize) -> Result<Self, VirtIOError> {
        unsafe {
            Ok(Self(UPSafeCell::new(VirtIOBlk::<VirtioHal>::new(
                &mut *(base_addr as *mut VirtIOHeader),
            )?)))
        }
    }
}

pub struct VirtioHal;

impl Hal for VirtioHal {
    /// allocate memory for virtio_blk device's io data queue
    fn dma_alloc(pages: usize) -> usize {
        let mut ppn_base = PhysPageNum(0);
        for i in 0..pages {
            let frame = frame_alloc().unwrap();
            if i == 0 {
                ppn_base = frame.ppn;
            }
            assert_eq!(frame.ppn.0, ppn_base.0 + i);
            QUEUE_FRAMES.exclusive_access().push(frame);
        }
        let pa: PhysAddr = ppn_base.into();
        pa.0
    }
    /// free memory for virtio_blk device's io data queue
    fn dma_dealloc(pa: usize, pages: usize) -> i32 {
        let pa = PhysAddr::from(pa);
        let mut ppn_base: PhysPageNum = pa.into();
        for _ in 0..pages {
            frame_dealloc(ppn_base);
            ppn_base.step();
        }
        0
    }
    /// translate physical address to virtual address for virtio_blk device
    fn phys_to_virt(addr: usize) -> usize {
        addr
    }
    /// translate virtual address to physical address for virtio_blk device
    fn virt_to_phys(vaddr: usize) -> usize {
        PageTable::from_token(kernel_token())
            .translate_va(VirtAddr::from(vaddr))
            .unwrap()
            .0
    }
}

