const BLOCK_SIZE: usize = 512;

lazy_static! {
    static ref EXT4_BOUNCE_BUFFER: UPSafeCell<[u8; BLOCK_SIZE]> =
        unsafe { UPSafeCell::new([0; BLOCK_SIZE]) };
    static ref EXT4_METADATA_CACHE: UPSafeCell<
        alloc::collections::BTreeMap<String, Option<Ext4Meta>>,
    > = unsafe { UPSafeCell::new(alloc::collections::BTreeMap::new()) };
    static ref EXT4_DIR_CACHE: UPSafeCell<
        alloc::collections::BTreeMap<String, Option<Vec<String>>>,
    > = unsafe { UPSafeCell::new(alloc::collections::BTreeMap::new()) };
}

#[derive(Debug)]
struct Ext4IoError;

impl Display for Ext4IoError {
    fn fmt(&self, f: &mut Formatter<'_>) -> FmtResult {
        write!(f, "ext4 io error")
    }
}

impl IoError for Ext4IoError {}

#[derive(Clone)]
struct Ext4BlockReader {
    dev: alloc::sync::Arc<dyn BlockDevice>,
}

impl Ext4Read for Ext4BlockReader {
    fn read(&mut self, start_byte: u64, dst: &mut [u8]) -> Result<(), Box<dyn IoError>> {
        if start_byte > usize::MAX as u64 {
            return Err(Box::new(Ext4IoError));
        }
        let mut pos = 0usize;
        while pos < dst.len() {
            let abs = start_byte as usize + pos;
            let block_id = abs / BLOCK_SIZE;
            let block_off = abs % BLOCK_SIZE;
            let mut block = EXT4_BOUNCE_BUFFER.exclusive_access();
            self.dev.read_block(block_id, &mut *block);
            let n = (dst.len() - pos).min(BLOCK_SIZE - block_off);
            dst[pos..pos + n].copy_from_slice(&block[block_off..block_off + n]);
            pos += n;
        }
        Ok(())
    }
}

fn with_ext4<T>(f: impl FnOnce(&Ext4) -> Option<T>) -> Option<T> {
    let reader = Ext4BlockReader {
        dev: TEST_BLOCK_DEVICE.clone(),
    };
    let fs = Ext4::load(Box::new(reader)).ok()?;
    f(&fs)
}

fn norm(path: &str) -> String {
    if path.starts_with('/') {
        path.to_string()
    } else {
        let mut s = String::from("/");
        s.push_str(path);
        s
    }
}

fn push_unique(out: &mut Vec<String>, value: String) {
    if !out.iter().any(|item| item == &value) {
        out.push(value);
    }
}

fn path_variants(path: &str) -> Vec<String> {
    let normalized = norm(path);
    let stripped = normalized
        .strip_prefix('/')
        .map(|s| s.to_string())
        .unwrap_or_else(|| normalized.clone());
    let mut variants = Vec::new();
    push_unique(&mut variants, normalized.clone());
    push_unique(&mut variants, stripped.clone());
    let dotted = if stripped.is_empty() {
        String::from(".")
    } else {
        format!("./{}", stripped)
    };
    push_unique(&mut variants, dotted);
    if normalized != "/" {
        push_unique(&mut variants, format!("{}/", normalized));
    }
    if !stripped.is_empty() {
        push_unique(&mut variants, format!("{}/", stripped));
        push_unique(&mut variants, format!("./{}/", stripped));
    }
    variants
}

/// Best-effort metadata for an ext4 path on the judge disk.
#[derive(Clone, Copy)]
pub struct Ext4Meta {
    /// Whether the path is a directory.
    pub is_dir: bool,
    /// Whether the path is a regular file.
    pub is_regular: bool,
    /// File length in bytes for regular files, or directory size as reported by ext4 metadata.
    pub len: usize,
}

/// Query metadata for a path on the judge ext4 disk.
pub fn ext4_metadata(path: &str) -> Option<Ext4Meta> {
    let cache_key = norm(path);
    if let Some(cached) = EXT4_METADATA_CACHE
        .exclusive_access()
        .get(cache_key.as_str())
        .cloned()
    {
        return cached;
    }
    for p in path_variants(path) {
        if let Some(meta) = with_ext4(|fs| {
            let md = fs.metadata(p.as_str()).ok()?;
            Some(Ext4Meta {
                is_dir: md.is_dir(),
                is_regular: md.file_type().is_regular_file(),
                len: md.len() as usize,
            })
        }) {
            EXT4_METADATA_CACHE
                .exclusive_access()
                .insert(cache_key, Some(meta));
            return Some(meta);
        }
    }
    EXT4_METADATA_CACHE
        .exclusive_access()
        .insert(cache_key, None);
    None
}

/// Read an ext4 file from judge disk into memory.
pub fn ext4_read_file(path: &str) -> Option<Vec<u8>> {
    for p in path_variants(path) {
        if let Some(data) = with_ext4(|fs| fs.read(p.as_str()).ok()) {
            return Some(data);
        }
    }
    None
}

/// List root directory entries from judge ext4 disk.
pub fn ext4_list_root() -> Option<Vec<String>> {
    ext4_list_dir("/")
}

/// List directory entries from a directory on judge ext4 disk.
pub fn ext4_list_dir(path: &str) -> Option<Vec<String>> {
    let cache_key = norm(path);
    if let Some(cached) = EXT4_DIR_CACHE
        .exclusive_access()
        .get(cache_key.as_str())
        .cloned()
    {
        return cached;
    }
    for p in path_variants(path) {
        if let Some(entries) = with_ext4(|fs| {
            let mut out = Vec::new();
            let rd = fs.read_dir(p.as_str()).ok()?;
            for ent in rd {
                let ent = ent.ok()?;
                let name = match ent.file_name().as_str() {
                    Ok(s) => s.to_string(),
                    Err(_) => continue,
                };
                out.push(name);
            }
            Some(out)
        }) {
            EXT4_DIR_CACHE
                .exclusive_access()
                .insert(cache_key, Some(entries.clone()));
            return Some(entries);
        }
    }
    EXT4_DIR_CACHE.exclusive_access().insert(cache_key, None);
    None
}

/// Return true if the given path is a readable directory on judge disk.
pub fn ext4_is_dir(path: &str) -> bool {
    ext4_metadata(path).map(|md| md.is_dir).unwrap_or(false) || ext4_list_dir(path).is_some()
}

/// Return true if the given path is a regular file on judge disk.
pub fn ext4_is_file(path: &str) -> bool {
    ext4_metadata(path).map(|md| md.is_regular).unwrap_or(false)
}

