/// Create a directory in the in-memory overlay if its parent exists.
pub fn mkdir_p(path: &str) -> bool {
    let path = canonicalize_path(path);
    if path == "/" || dir_exists(path.as_str()) {
        return true;
    }
    if !mem_parent_exists(path.as_str()) {
        return false;
    }
    DELETED_PATHS.exclusive_access().remove(path.as_str());
    MEM_DIRS.exclusive_access().insert(path);
    true
}

/// Create a symbolic link in the in-memory overlay if its parent exists.
pub fn symlink_path(target: &str, link: &str) -> bool {
    let link = canonicalize_path(link);
    if !mem_parent_exists(link.as_str())
        || dir_exists(link.as_str())
        || mem_file_exists(link.as_str())
        || path_is_symlink(link.as_str())
    {
        return false;
    }
    DELETED_PATHS.exclusive_access().remove(link.as_str());
    SYMLINKS.exclusive_access().insert(link, target.to_string());
    true
}

/// Remove a file or directory from the in-memory overlay.
pub fn remove_path(path: &str) -> bool {
    let path = canonicalize_path(path);
    DELETED_PATHS.exclusive_access().remove(path.as_str());
    if MEM_FILES.exclusive_access().remove(path.as_str()).is_some() {
        let group = LINK_GROUPS.exclusive_access().remove(path.as_str());
        FILE_META.exclusive_access().remove(path.as_str());
        if let Some(group) = group {
            refresh_link_counts(group.as_str());
        }
        return true;
    }
    if SYMLINKS.exclusive_access().remove(path.as_str()).is_some() {
        FILE_META.exclusive_access().remove(path.as_str());
        return true;
    }
    if MEM_DIRS.exclusive_access().remove(path.as_str()) {
        return true;
    }
    if ext4::ext4_is_file(path.as_str())
        || ext4::ext4_is_dir(path.as_str())
        || ext4_dir_entries(path.as_str()).is_some()
    {
        DELETED_PATHS.exclusive_access().insert(path);
        return true;
    }
    false
}

/// Reset the in-memory writable overlay between independent tests.
pub fn reset_overlay() {
    MEM_FILES.exclusive_access().clear();
    let mut dirs = MEM_DIRS.exclusive_access();
    dirs.clear();
    dirs.insert(String::from("/"));
    dirs.insert(String::from("/tmp"));
    drop(dirs);
    DELETED_PATHS.exclusive_access().clear();
    FILE_META.exclusive_access().clear();
    LINK_GROUPS.exclusive_access().clear();
    SYMLINKS.exclusive_access().clear();
}

